import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.Scanner;
import java.util.TreeMap;

public class Main {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        String input = scanner.nextLine();
        String[] fileInfos = input.split(",");

        Map<String, List<String>> contentPaths = new HashMap<>();
        for (String fileInfo : fileInfos) {
            String[] fileInfoParts = fileInfo.split(" ");
            String directory = fileInfoParts[0];
            for (int i = 1; i < fileInfoParts.length; i++) {
                String file = fileInfoParts[i];
                int index = file.indexOf("(");
                String fileName = file.substring(0, index);
                String content = file.substring(index + 1, file.length() - 1);
                String filePath = directory + "/" + fileName;
                if (!contentPaths.containsKey(content)) {
                    contentPaths.put(content, new ArrayList<>());
                }
                contentPaths.get(content).add(filePath);
            }
        }

        List<String> duplicateFiles = new ArrayList<>();
        for (Map.Entry<String, List<String>> entry : contentPaths.entrySet()) {
            if (entry.getValue().size() > 1) {
                duplicateFiles.add(entry.getKey() + ":" + entry.getValue());
            }
        }

        duplicateFiles.sort((f1, f2) -> {
            String content1 = f1.substring(0, f1.indexOf(":"));
            String content2 = f2.substring(0, f2.indexOf(":"));
            return content1.compareTo(content2);
        });

        for (String duplicateFile : duplicateFiles) {
            System.out.println(duplicateFile);
        }
    }
}
