import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.Scanner;

public class Main {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        String input = scanner.nextLine();

        Map<String, Object> dictionary = evalDictString(input);
        Map<String, Object> newDictionary = checkDictValues(dictionary);

        System.out.println(newDictionary);
    }

    public static Map<String, Object> evalDictString(String dictString) {
        dictString = dictString.replace("{", "").replace("}", "");
        String[] splitDict = dictString.split(", ");
        Map<String, Object> dictionary = new HashMap<>();

        for (String item : splitDict) {
            String[] keyValue = item.split(": ");
            String key = keyValue[0];
            String value = keyValue[1];

            if (value.startsWith("[")) {
                value = value.substring(1, value.length() - 1);
                String[] valueArray = value.split(", ");
                dictionary.put(key, valueArray);
            } else {
                dictionary.put(key, value);
            }
        }

        return dictionary;
    }

    public static Map<String, Object> checkDictValues(Map<String, Object> dictionary) {
        Map<String, Object> newDictionary = new HashMap<>();
        for (Map.Entry<String, Object> entry : dictionary.entrySet()) {
            String key = entry.getKey();
            Object value = entry.getValue();

            if (value instanceof String && isNumeric((String) value)) {
                newDictionary.put(key, value);
            } else if (value instanceof List) {
                List<String> valueList = (List<String>) value;
                if (hasNumericElement(valueList)) {
                    newDictionary.put(key, valueList);
                }
            }
        }
        return newDictionary;
    }

    public static boolean isNumeric(String strNum) {
        try {
            Integer.parseInt(strNum);
        } catch (NumberFormatException | NullPointerException nfe) {
            return false;
        }
        return true;
    }

    public static boolean hasNumericElement(List<String> list) {
        for (String element : list) {
            if (isNumeric(element)) {
                return true;
            }
        }
        return false;
    }
}
